+export type RatingValue = "up" | "down";
+
+export type RatingContentType =
+  | "prompt"
+  | "bundle"
+  | "workflow"
+  | "collection"
+  | "skill";
+
+export const RATING_CONTENT_TYPES: RatingContentType[] = [
+  "prompt",
+  "bundle",
+  "workflow",
+  "collection",
+  "skill",
+];
+
+export function isRatingContentType(value: string): value is RatingContentType {
