+}
+
+export interface ContentRating {
+  id: string;
+  contentType: RatingContentType;
+  contentId: string;
+  userId: string;
+  value: RatingValue;
+  createdAt: string;
+  updatedAt: string;
+}
+
+export interface RatingSummary {
+  contentType: RatingContentType;
+  contentId: string;
+  upvotes: number;
+  downvotes: number;
